        <div class="dna-field"><label>Border width</label><div class="dna-pills">${['none','hairline','thin','bold'].map(t=>`<button class="dna-pill ${_DNA.borderWidth===t?'on':''}" data-pill="borderWidth" data-val="${t}">${t}</button>`).join('')}</div></div>
